// TestScore_SupportedLanguage_StillWorks is a regression guard that ensures
// a realistic Go unit with multiple evidence kinds still produces a valid
// certification record (non-zero grade, non-zero status, positive weighted avg).
func TestScore_SupportedLanguage_StillWorks(t *testing.T) {
	unit := domain.NewUnit(
		domain.NewUnitID("go", "main.go", "main"),
		domain.UnitTypeFunction,
	)

	ev := []domain.Evidence{
		evidence.CodeMetrics{Complexity: 15, CodeLines: 120, TotalLines: 150}.ToEvidence(),
		evidence.GitStats{CommitCount: 42, AuthorCount: 3, AgeDays: 90}.ToEvidence(),
		evidence.LintResult{Tool: "golangci-lint", ErrorCount: 0}.ToEvidence(),
	}

	record := engine.CertifyUnit(unit, []domain.PolicyRule{}, ev, domain.ExpiryConfig{DefaultWindowDays: 90}, time.Now())

	// The record must carry evidence that the pipeline processed.
	if len(record.Evidence) == 0 {
		t.Error("expected evidence on the record, got none")
	}

	// Dimensions must be non-empty (scoring ran).
	if len(record.Dimensions) == 0 {
		t.Error("expected dimension scores to be populated, got empty map")
	}

	// The weighted-average score must be positive.
	if record.Score <= 0 {
		t.Errorf("expected Score > 0, got %f", record.Score)
	}
}

// TestScore_DefaultsNotInjected guards against the former 0.5 default injection.
// A unit with only one evidence kind (structural, no code metrics) should not
// receive 0.5 for any dimension. Dimensions without evidence are simply absent.
func TestScore_DefaultsNotInjected(t *testing.T) {
	ev := []domain.Evidence{
		{
			Kind:   domain.EvidenceKindStructural,
			Source: "structural",
			Passed: true,
			Metrics: map[string]float64{
				"method_count":      5,
				"context_not_first": 0,
			},
		},
	}

	scores := engine.Score(ev, policy.EvaluationResult{})

	// No dimension should be exactly 0.5 (the former default).
	for dim, val := range scores {
		if val == 0.5 {
			t.Errorf("dimension %s has score 0.5 — former default injection detected", dim)
		}
	}

	// Only dimensions backed by evidence should be present.
	// With only structural (clean method_count <= 15, no context_not_first violation),
	// we expect a small number of dimensions.
	if len(scores) == 0 {
		t.Error("expected at least some dimensions from structural evidence, got none")
	}
}

// BUG(iksnae/code-certification#25): scoreFromMetrics incorrectly assigns
// excellent (0.95) maintainability when complexity=0 for unmeasured languages.
//
// TestScore_UnmeasuredComplexity_NotScoredExcellent documents the complexity=0 bug.
// When a code metrics evidence carries complexity=0 (e.g. a Swift or generic file
// where no complexity analyzer ran), maintainability should NOT be scored as
// excellent. Today the scorer DOES assign 0.95 (the bug). This test records
// the current (wrong) behavior so it can be flipped when the bug is fixed.
func TestScore_UnmeasuredComplexity_NotScoredExcellent(t *testing.T) {
	ev := []domain.Evidence{
		{
			Kind:   domain.EvidenceKindMetrics,
			Source: "generic",
			Passed: true,
			Metrics: map[string]float64{
				"complexity": 0,
				"coverage":   0,
			},
		},
	}

	scores := engine.Score(ev, policy.EvaluationResult{})

	// BUG(iksnae/code-certification#25): complexity=0 (unmeasured) should NOT
	// produce maintainability=0.95, but currently does. When the bug is fixed,
	// flip this assertion to: if v, ok := scores[domain.DimMaintainability]; ok && v == 0.95 { t.Error(...) }
	if v, ok := scores[domain.DimMaintainability]; !ok || v != 0.95 {
		t.Logf("BUG #25 appears fixed: maintainability=%v (present=%v) — update this test!", v, ok)
	}
}

